const binaryData = $input.item.binary;
const image = binaryData && binaryData.image ? binaryData.image : null;
const body = $input.item.json.body || {};

return [{
  json: {
    hasImage: !!image,
    imageMimeType: image?.mimeType || null,
    imageData: image?.data || null,
    query: body.query || "",
    sessionId: body.sessionId || "unknown",
    userName: body.userName || "Usuario",
    userEmail: body.userEmail || "no-email@satcomla.com",
    chatHistory: $input.all().map(i => i.json).filter(msg => msg.role).reverse()
  }
}];

