const results = $input.all().map(i => i.json);
const input = $('Process Input').item.json;

if (!results || results.length === 0) {
  return [{
    json: {
      contexto: '',
      images: [],
      sourceUrl: '',
      sinResultados: true,
      ...input
    }
  }];
}

const textChunks = results.filter(r => r.type === 'text').slice(0, 6).map(r => r.content);
const imageResults = results.filter(r => r.type === 'image');
const images = imageResults.map((r, i) => ({
  index: i + 1,
  filename: r.metadata?.image_filename || `imagen_${i+1}.jpg`,
  imageUrl: r.metadata?.image_url || null,
  base64: r.metadata?.original_content || null,
  sourceUrl: r.metadata?.source_url || ""
})).slice(0, 4);

return [{
  json: {
    contexto: textChunks.join('\n\n---\n\n'),
    images,
    sourceUrl: results[0]?.metadata?.source_url || "",
    sinResultados: false,
    ...input
  }
}];

const { contexto, images, query, hasImage, imageData, imageMimeType, chatHistory, userName } = $json;

const imageListForPrompt = images.length > 0
  ? `\n\nIMAGENES DISPONIBLES DEL MANUAL:\n${images.map(img => `  [${img.index}] ${img.filename}`).join('\n')}\nSi alguna imagen es relevante para tu respuesta, incluyela con [ENVIAR_IMAGENES: N] donde N son los indices separados por coma.`
  : '';

const systemInstruction = `Eres SARA, una asistente inteligente experta en los manuales de la empresa.
Tu objetivo es ser conversacional, amable y precisa.

Estás hablando con ${userName || 'un usuario'}.

REGLAS DE ORO:
1. Si el usuario te envia una imagen, analizala primero. El contexto del RAG puede contener informacion sobre esa imagen.
2. Solo menciona la fuente del manual cuando tu respuesta se basa directamente en la documentacion.
3. Si es charla casual (hola, gracias, etc.), responde de forma natural sin citar manuales.
4. Si hay imagenes disponibles del manual que complementen tu respuesta, incluyelas usando el marcador [ENVIAR_IMAGENES: N] con los indices correspondientes. Solo hazlo si realmente aportan valor visual.
5. No inventes informacion. Si no encuentras la respuesta en el contexto, dilo honestamente.`;

let contents = [];
chatHistory.forEach(msg => {
  if (msg.content) {
    contents.push({ role: msg.role === 'assistant' ? 'model' : 'user', parts: [{ text: msg.content }] });
  }
});

let userParts = [];
if (hasImage) {
  userParts.push({ inline_data: { mime_type: imageMimeType, data: imageData } });
}

let fullPrompt = query;
if (contexto) {
  fullPrompt = `CONTEXTO DEL MANUAL:\n${contexto}${imageListForPrompt}\n\nCONSULTA: ${query}`;
}
userParts.push({ text: fullPrompt });

contents.push({ role: 'user', parts: userParts });

return [{
  json: {
    gemini_body: {
      system_instruction: { parts: [{ text: systemInstruction }] },
      contents,
      generationConfig: { temperature: 0.2, maxOutputTokens: 2048 }
    },
    images,
    sourceUrl: $json.sourceUrl
  }
}];

// Obtener images y sourceUrl del nodo correcto
const images = $('Preparar Body LLM').item.json.images || [];
const sourceUrl = $('Preparar Body LLM').item.json.sourceUrl || '';
const sessionId = $('Process Input').item.json.sessionId;
const candidates = $json.candidates;

if (!candidates || candidates.length === 0) {
  return [{ json: { response: 'Error de IA', images: [], sources: [], sessionId } }];
}

let text = candidates[0].content.parts[0].text;

// Parsear marcadores [ENVIAR_IMAGENES: 1,2,3]
const imageMatch = text.match(/\[ENVIAR_IMAGENES:\s*([\d,\s]+)\]/i);
let selectedImages = [];
if (imageMatch && images.length) {
  const indices = imageMatch[1].split(',').map(n => parseInt(n.trim())).filter(n => !isNaN(n));
  selectedImages = indices.map(i => images[i - 1]).filter(Boolean);
}

// Limpiar marcadores del texto
let finalResponse = text.replace(/\[ENVIAR_IMAGENES:[\d,\s]+\]/gi, '').trim();

// Determinar si mostrar fuentes
const searchResults = $('Supabase Search').all();
const isDocResponse = searchResults.length > 0 && finalResponse.length > 50 && sourceUrl;

return [{
  json: {
    response: finalResponse,
    sessionId,
    images: selectedImages.map(img => ({
      url: img.imageUrl || null,
      base64: img.base64 || null,
      filename: img.filename || null,
      sourceUrl: img.sourceUrl || ''
    })),
    sources: isDocResponse ? [{ url: sourceUrl, title: 'Ver manual original' }] : []
  }
}];
